#include <iostream>
#include <vector>
#include <cmath>

using namespace std;

// Function to generate a modified Fibonacci sequence
vector<int> generateModifiedFibonacci(int n) {
    vector<int> fib;
    int a = 1, b = 1;
    for (int i = 0; i < n; ++i) {
        fib.push_back(a);
        int next = a + b;
        a = b;
        b = next;
    }
    return fib;
}

// Function to generate a spiral pattern based on the sequence
void generateSpiralPattern(vector<int> &sequence, int size) {
    char patternChar = '*';
    int x = 0, y = 0;
    int dx = 0, dy = 1;
    int steps = 1;
    int stepCount = 0;

    vector<vector<char>> grid(size, vector<char>(size, ' '));

    for (int i = 0; i < sequence.size(); ++i) {
        for (int j = 0; j < sequence[i]; ++j) {
            if (x >= 0 && x < size && y >= 0 && y < size) {
                grid[x][y] = patternChar;
            }
            x += dx;
            y += dy;
            stepCount++;
            if (stepCount == steps) {
                stepCount = 0;
                int temp = dx;
                dx = -dy;
                dy = temp;
                steps++;
            }
        }
    }

    for (int i = 0; i < size; ++i) {
        for (int j = 0; j < size; ++j) {
            cout << grid[i][j];
        }
        cout << endl;
    }
}

// Recursive function to generate nested patterns
void nestedPattern(int depth, int size) {
    if (depth == 0) return;
    vector<int> sequence = generateModifiedFibonacci(depth * 2);
    generateSpiralPattern(sequence, size);
    nestedPattern(depth - 1, size - 2);
}

